<?php declare(strict_types=1);
namespace MOJ\JudicialSystem;
use PhpOffice\PhpSpreadsheet\Spreadsheet;use PhpOffice\PhpSpreadsheet\Writer\Xlsx;
final class Exporter{public function csv(array $rows):string{$f=fopen('php://temp','r+');if($rows){fputcsv($f,array_keys($rows[0]));foreach($rows as $r){fputcsv($f,$r);}}rewind($f);return stream_get_contents($f)?:'';} public function json(array $rows):string{return json_encode($rows,JSON_UNESCAPED_UNICODE|JSON_PRETTY_PRINT)?:'[]';} public function xml(array $rows):string{$xml=new \SimpleXMLElement('<decisions/>');foreach($rows as $row){$n=$xml->addChild('decision');foreach($row as $k=>$v){$n->addChild((string)$k,htmlspecialchars((string)$v));}}return $xml->asXML()?:'';} public function excel(array $rows,string $path):string{$sheet=(new Spreadsheet())->getActiveSheet();if($rows){$sheet->fromArray(array_keys($rows[0]),null,'A1');$sheet->fromArray(array_map('array_values',$rows),null,'A2');}(new Xlsx($sheet->getParent()))->save($path);return $path;}}
